1	import { describe, it, expect } from "vitest";
2	import { nextGeneration, type Cell } from "./game-of-life.js";
3	
4	describe("Game of Life - nextGeneration", () => {
5	  it("should return empty array when given empty input", () => {
6	    expect(nextGeneration([])).toEqual([]);
7	  });
8	  it("should kill a single live cell with no neighbors (underpopulation)", () => {
9	    expect(nextGeneration([[0, 0]])).toEqual([]);
10	  });
11	  it("should kill two adjacent cells each with only 1 neighbor (underpopulation)", () => {
12	    expect(nextGeneration([[0, 1], [1, 1]])).toEqual([]);
13	  });
14	  it("should keep a live cell alive when it has 2 live neighbors (survival)", () => {
15	    // Vertical blinker: middle cell (0,1) has 2 neighbors, survives
16	    const result = nextGeneration([[0, 0], [0, 1], [0, 2]]);
17	    expect(result).toContainEqual([0, 1]);
18	  });
19	  it("should kill a live cell with more than 3 neighbors (overpopulation)", () => {
20	    // 3x3 filled: center (1,1) has 8 neighbors → dies
21	    const cells: Cell[] = [
22	      [0, 0], [1, 0], [2, 0],
23	      [0, 1], [1, 1], [2, 1],
24	      [0, 2], [1, 2], [2, 2],
25	    ];
26	    expect(nextGeneration(cells)).not.toContainEqual([1, 1]);
27	  });
28	  it.todo("should bring a dead cell to life when it has exactly 3 live neighbors (reproduction)");
29	  it.todo("should preserve a block still life across a generation");
30	  it.todo("should oscillate a vertical blinker into a horizontal blinker");
31	  it.todo("should handle negative coordinates correctly");
32	});
